column30:
For fast resolution of issues, we require CRUD access to Solvit API endpoints. We shall use the same format as in Swagger, but for Admin. To start with, kindly share the following endpoints: 

# Admin Authentication - {{/api/admin-login}}
# Request Details - {{/api/request/detail}}
# Initiate Request - {{/api/request/insurance-initiate-request}}
# Schedule Initiate request - {{/api/request/schedule-initiate-request}}
# Initiate request list by ID {{/api/request/initiate-request-list-by-id}}
# Cancel by initiate request ID {{/api/request/cancel-initiate-request}}
# Valuation detail list by inspection date {{/api/request/valuation-detail-list }}
# Valuation detail list by approval *date-time* {{/api/request/valuation-list-by-approval-date-time}}

{code:javascript}import { Injectable } from "@angular/core";
import { environment } from "../../../../environments/environment";
import { VehicleValues } from "./vehicle-values.model";
import moment from "moment";

@Injectable({
  providedIn: "root"
})

export class ValuationService {
  constructor() {}
  public calculateVehicleValue(vehicle: VehicleValues) {
    const import_value = vehicle.import_value;
    const current_retail_selling_price = vehicle.current_retail_selling_price;
    const customs_value = vehicle.customs_value;
    const dealership_value = vehicle.dealership_value;
    const engine_size = vehicle.engine_size;
    const vehicle_size = vehicle.vehicle_size;
    const vehicle_use = vehicle.vehicle_use;
    const mileage_in_km_per_year = vehicle.mileage;
    const year_of_manufacture = vehicle.year_of_manufacture;
    const date_of_registration = new Date(vehicle.date_of_registration);
    const vehicle_age_by_manufature_in_years = new Date().getFullYear() - year_of_manufacture;
    const vehicle_age_in_months = getAgeinMonths(date_of_registration);
    const country_of_origin = vehicle.country_of_origin;
    const country_of_valuation = vehicle.country_of_valuation;
    const total_taxes = 0;
    const body_faults = vehicle.body_faults;
    const body_faults_severity = body_faults === 0 ? "No" : body_faults === 1 ? "Minor" : "Major";
    const engine_faults = vehicle.engine_faults;
    const transmission_faults = vehicle.transmission_faults;
    const steering_faults = vehicle.steering_faults;
    const demand = vehicle.demand;
    const is_roadworthy = vehicle.is_roadworthy;
    const previous_value = vehicle.previous_value;
    const average_value = vehicle.average_value;
    const auto_approve_status = vehicle.auto_approve_status;
    const fuel_type = vehicle.fuel_type;
    //Get environment variables
    const freight_value = environment.freight_country_amount[country_of_valuation][vehicle_size];
    const mileage_object = environment.high_mileage[country_of_valuation][vehicle_use];
    const mileage_value_range = get_mileage_value_range(mileage_in_km_per_year, mileage_object);
    const mileage_depreciator_percent = environment.high_mileage[country_of_valuation][vehicle_use][mileage_value_range];
    const body_faults_depreciator = body_faults ? environment.body_faults[body_faults] : 0;
    const engine_faults_depreciator = engine_faults ? environment.engine_faults : 0;
    const transmission_faults_depreciator = transmission_faults ? environment.transmission_faults : 0;
    const steering_faults_depreciator = steering_faults ? environment.steering_faults : 0;
    const unroadworthy_depreciator = is_roadworthy ? 0 : environment.unroadworthiness;

    const get_demand_factor = (demandfactor)=> {
      if (demandfactor == 0){
        return environment.demand_factor[0];
      } else if (demandfactor == 1){
        return environment.demand_factor[1] }
      else if ( demandfactor == 2){
        return environment.demand_factor[2]
      } else {
        return null;
      }
    }

    const depreciation_rate_by_vehicle_age = country_of_origin == country_of_valuation ? environment.depreciating_factor_by_vehicle_age[country_of_valuation][vehicle_age_by_manufature_in_years] : 0;
    const depreciation_rate_by_vehicle_use = environment.depreciation_by_use[vehicle_use];
    //Call calculation logic
    const calculated_import_value = country_of_origin != country_of_valuation ? calculate_import_value(import_value, customs_value, freight_value, country_of_valuation) : 0;
    console.log("Import_value: ", import_value, ",\nCustoms_value: ",customs_value, ",\nFreight_value: ", freight_value, "\nCountry of origin: ", country_of_origin,",\nCountry_of_valuation: ",country_of_valuation, ",\nAppreciated_import_value: ",calculated_import_value);
    const depreciated_crsp_value =  depreciate_crsp_value(vehicle_age_by_manufature_in_years, current_retail_selling_price, depreciation_rate_by_vehicle_use);
    console.log("Current_retail_selling_price: ", current_retail_selling_price, "\n x 1 - (Depreciation_rate_by_vehicle_use: ",depreciation_rate_by_vehicle_use,")\n^ Vehicle age in years ",vehicle_age_by_manufature_in_years,": \nDepreciated_crsp_value: = ",depreciated_crsp_value);
    const depreciated_local_value = getLocalValue(dealership_value, depreciation_rate_by_vehicle_age, vehicle_age_in_months);
    console.log("Dealership_value: ", dealership_value, ",\nDepreciation_rate_by_vehicle_age", depreciation_rate_by_vehicle_age, ",\nVehicle_age_in_months: ", vehicle_age_in_months, ",\nDepreciated_local_value: = ",depreciated_local_value);
    //Get calculated value based on country of origin
   const calculated_value = +getCalculatedValue(calculated_import_value, depreciated_crsp_value, depreciated_local_value, country_of_origin == country_of_valuation);
   console.log("Calculated_value",calculated_value);
    //Calculate depreciation or appreciation by grade
    const mileage_depreciation_value = mileage_depreciation(calculated_value, mileage_depreciator_percent);
    const unroadworthiness_depreciation_value = 0;
    //const unroadworthiness_depreciation_value = unroadworthiness_depreciation(calculated_value, unroadworthy_depreciator);
    const demand_factor_appreciation_or_depreciation_value = demand_factor_appreciation_or_depreciation(calculated_value, get_demand_factor(vehicle.demand), vehicle.rare_model_depreciation);
    const steering_faults_depreciation_value =  steering_faults_depreciation(calculated_value, steering_faults_depreciator)
    const transmission_faults_depreciation_value =  0;
    //const transmission_faults_depreciation_value =  transmission_faults_depreciation(calculated_value, transmission_faults_depreciator);
    const engine_faults_depreciation_value =  0;
    //const engine_faults_depreciation_value =  engine_faults_depreciation(calculated_value, engine_faults_depreciator);
    const body_faults_depreciation_value = body_faults_depreciation(calculated_value, body_faults_depreciator);
    const depreciated_calculated_value_by_grade = depreciate_vehicle_by_grade(calculated_value);

    const calculated_vehicle_values = {
      "make":vehicle.make,
      "model":vehicle.model,
      "year_of_manufacture":vehicle.year_of_manufacture,
      "year_of_registration":vehicle.date_of_registration,
      "vehicle_size": vehicle.vehicle_size,
      "vehicle_use": vehicle.vehicle_use,
      "country_of_origin":country_of_origin,
      "import_value":import_value,
      "customs_value":customs_value,
      "crsp_value": current_retail_selling_price,
      "freight_value":freight_value,
      "total_depreciation_value": total_taxes,
      "appreciated_import_value":calculated_import_value,
      "depreciated_crsp_value":depreciated_crsp_value,
      "depreciated_calcualted_value_by_grade":depreciated_calculated_value_by_grade,
      "previous_value":previous_value,
      "average_value":average_value,
      "body_faults": body_faults,
      "engine_faults": engine_faults,
      "transmission_faults": transmission_faults,
      "steering_faults": steering_faults,
      "demand": demand,
      "is_roadworthy": is_roadworthy,
      "auto_approve_status": auto_approve_status,
      "engine_size":engine_size,
      "mileage_in_km_per_year":mileage_in_km_per_year,
      "country_of_valuation":country_of_valuation,
      "mileage_depriciation":mileage_depreciation_value,
      "unroadworthiness_value":unroadworthiness_depreciation_value,
      "demand_factor":demand_factor_appreciation_or_depreciation_value,
      "steering_faults_depreciation":steering_faults_depreciation_value,
      "transmission_faults_depreciation":transmission_faults_depreciation_value,
      "engine_faults_depreciation":engine_faults_depreciation_value,
      "body_faults_depreciation":body_faults_depreciation_value,
      "calculated_value":calculated_value,
      "body_faults_narrative":body_faults_severity + " body faults: " + body_faults_depreciator + "%",
      "engine_faults_narrative":(engine_faults ? "Engine faults: " + engine_faults_depreciator + "%" : "No engine faults"),
      "steering_faults_narrative":(steering_faults ? "Steering faults: " + steering_faults_depreciator + "%" : "No steering faults"),
      "transmission_faults_narrative":(transmission_faults ? "Transmission faults: " + transmission_faults_depreciator + "%" : "No transmission faults"),
      "unroadworthiness_narrative":!is_roadworthy ? "Unroadworthy: " + unroadworthy_depreciator + "%" : "Roadworthy, no depreciation",
      "demand_factor_narrative":demand == 0 ? "Average demand, no depreciation or appreciation" : demand == 1 ? "High demand: +" + get_demand_factor(1) + "%" :  demand == 2 ? "Low demand: "+ get_demand_factor(2)+ "%" : "Rare demand depreciation: " + vehicle.rare_model_depreciation + "%",
      "mileage_factor_narrative":"Mileage appreciation or depreciation: " + mileage_depreciator_percent + "%",
      "dealership_value": dealership_value,
      "depreciated_local_value": depreciated_local_value,
    };

  function calculate_import_value(import_value:number, customs_value: number, freight_value: number, country: number){
    //Means vehicle is imported
    //Add the freight value to the import value based on the country and size of vehicle. The figures are country specific.
    if(import_value != 0 && customs_value != 0 && freight_value != 0 && country != 0){
      const cif_value = +import_value + +freight_value;
      console.log("1. freight value: ", freight_value);
      console.log("1a. import_plus_freight_value: ",cif_value);
      //Appreciate the yearly local value for the specific country to get the total taxes that will then be added to the import_plus_freight_value
      const customs_percent = (+environment.customs_percent[country] + 100)/100;
      const add_import_duty = vehicle_age_by_manufature_in_years > environment.max_local_allowed_age[country_of_valuation] ? cif_value * customs_percent :  customs_value * customs_percent;
      console.log("CIF", cif_value, "Customs Value", customs_value);
      console.log("2. Max_local_allowed_age = ",environment.max_local_allowed_age[country_of_valuation],", Import duty for vehicle_age_by_manufature_in_years",vehicle_age_by_manufature_in_years,", Customs_percent for country of valuation ", country_of_valuation," = ", customs_percent, "%, add customs = ", add_import_duty);
      //Add customs duty
      const high_cc_based_on_fuel_type = environment.high_cc_by_fuel[fuel_type];
      const is_high_mileage = engine_size > high_cc_based_on_fuel_type
      const excise_duty_percentage = is_high_mileage ? environment.excise_duty_percemnt_by_size[1] : environment.excise_duty_percemnt_by_size[2];
      const add_excise_duty = +add_import_duty * ((excise_duty_percentage + 100)/100);
      console.log (+add_import_duty,+environment.excise_duty_percentage[country]);
      console.log("3. Excise @ ", excise_duty_percentage,"% = ", add_excise_duty);
      //Add VAT
      const add_vat = +add_excise_duty * ((+environment.vat_percentage[country] + 100)/100);
      console.log("4. VAT @ ",+environment.vat_percentage[country]," % = ", add_vat);
      const add_import_declaration = +add_vat * ((+environment.import_declaration_fees[country] + 100)/100);
      console.log("5. Import_declaration @ ",environment.import_declaration_fees," % = ", add_import_declaration);
      const add_railway_development_levy = +add_import_declaration * ((+environment.railway_development_levy[country] + 100)/100);
      console.log("6. railway_development_levy @ ",environment.railway_development_levy," % = ", add_railway_development_levy);
      //Add sales margin
      const add_sales_margin = +add_railway_development_levy * ((+environment.sales_margin_percent[country]+100)/100);
      console.log("7. Sales margin @ ", environment.sales_margin_percent[country], "% = ", add_sales_margin);
      //Tax is calculated based on the yearly local selling price of the car
      const total_taxes = +add_sales_margin - +customs_value;
      console.log("8. Total taxes = ",total_taxes);

      //Add the taxes to the import_plus_freight_value
    const appreciated_import_value = +cif_value + +total_taxes;
      console.log("9. Appreciated import value: ",appreciated_import_value);
      return appreciated_import_value;
    }
    return 0;
  }

  function depreciate_crsp_value(vehicle_age_in_years: number, crsp_value: number, depreciation_rate: number) :number{
    //depreciate_crsp_value = value (1-depreciation_rate) ^ vehicle_age_in_years +/- (adjustments)
    const depreciated_crsp_value = crsp_value * Math.pow(1+(depreciation_rate/100),vehicle_age_in_years);
    //console.log("depreciated crsp value:",depreciated_crsp_value + "\n\n");
    return depreciated_crsp_value;
  }

  function getLocalValue(dealer_price: number, depreciation_factor: number, vehicle_age_in_months: number){
    const local_value = vehicle_age_in_months < 36 ? dealer_price * depreciation_factor * vehicle_age_in_months: dealer_price * depreciation_factor;
    //console.log("calculated local_value: ",local_value);
    return local_value;
  }

  function getCalculatedValue(calculated_import_value: number, depreciated_crsp_value: number, depreciated_local_value: number, is_local: boolean) : number{
    if(is_local){
      return depreciated_local_value
    } else {
      //Vehicle is imported
      if(calculated_import_value == 0 && depreciated_crsp_value == 0){
        return 0;
      } else if(calculated_import_value > depreciated_crsp_value){
        return depreciated_crsp_value;
      } else {
        return calculated_import_value;
      }
    }
  }

  function getAgeinMonths(startDate: Date){
    return moment().diff(moment(startDate), 'month', true);
  }

  function depreciate_vehicle_by_grade(value: number){
    return value +
    mileage_depreciation_value +
    unroadworthiness_depreciation_value +
    demand_factor_appreciation_or_depreciation_value +
    steering_faults_depreciation_value +
    transmission_faults_depreciation_value +
    engine_faults_depreciation_value +
    body_faults_depreciation_value;
  }

  function get_mileage_value_range(mileage_in_kms_per_year, values_object: {}){
    const values_array = Object.keys(values_object);
    var value;
    for (var i = 0; i < values_array.length; i++){
      if(mileage_in_kms_per_year > values_array[i-1] && mileage_in_kms_per_year <= values_array[i]){
        value = values_array[i];
        console.log("Mileage range: ",values_array[i-1], " - ", values_array[i]);
        break;
      }
    }
    return value;
  }

  function mileage_depreciation(value: number, mileage_depreciator: number){
    const mileage_depreciation = value * (mileage_depreciator /100);
    console.log("Mileage depreciation factor: " + mileage_depreciator, "\nMileage depreciation or appreciation: ", mileage_depreciation);
    return  mileage_depreciation;
  }

  function body_faults_depreciation(value: number, body_fault_depreciator: number){
    const body_faults_depreciation = value * (body_fault_depreciator /100);
    console.log("\nBody_fault_depreciator: ", body_fault_depreciator, "\nBody_faults_depreciation: ", body_faults_depreciation);
    return body_faults_depreciation;
  }

  function engine_faults_depreciation(value: number,engine_fault_depreciator: number){
    const engine_faults_depreciation = value * (engine_fault_depreciator/100);
    console.log("engine_faults_depreciation: ", engine_faults_depreciation);
    return engine_faults_depreciation;
  }

  function transmission_faults_depreciation(value: number, transmission_fault_depreciator: number){
    const transmission_faults_depreciation = value * (transmission_fault_depreciator /100);
    console.log("transmission_faults_depreciation: ", transmission_faults_depreciation);
    return transmission_faults_depreciation;
  }

  function steering_faults_depreciation(value: number, steering_fault_depreciator: number){
    const steering_faults_depreciation = value * (steering_fault_depreciator/100);
    console.log("Steering_faults_depreciation: ", steering_faults_depreciation);
    return steering_faults_depreciation;
  }

  function demand_factor_appreciation_or_depreciation(value: number, demand_factor: number, rare_model_depreciation: number){
    const demand_value = demand_factor == null ? value * (rare_model_depreciation/100) : value * (demand_factor/100);
    console.log("Rare model depreciation: ", rare_model_depreciation, ",\nDemand factor depreciation or appreciation:", demand_factor, ",\nDemand factor value: ", demand_value);
    return demand_value;
  }

  function unroadworthiness_depreciation(value: number, unroadworthiness_depreciator: number){
    const unroadworthiness_value = value * (unroadworthiness_depreciator/100);
    console.log("unroadworthiness_depreciation: ", unroadworthiness_value + "\n\n");
    return unroadworthiness_value;
  }
    return calculated_vehicle_values;
  }
}

export const environment = {
  production: false,
  firebaseConfig: {
    //
  },

  countries: {
    "Kenya": 254,
    "Japan": 81,
  },
  //Key - freight_country_amount 1: Small, 2: Medium, 3: Large, 4: Big truck
  freight_country_amount: {254:{1:100000, 2:120000, 3:150000, 4:400000}},
  //high_cc_by_fuel Petrol: 1, Diesel: 2
  high_cc_by_fuel: {1: 2500, 2: 3000},
  //excise_duty_percent_by_size High: 1, Low: 2:
  excise_duty_percemnt_by_size: {1: 30, 2: 20},
  customs_percent: {254:25},
  excise_duty_percentage: {254:30},
  sales_margin_percent: {254:10},
  import_declaration_fees: {254: 2},
  railway_development_levy: {254: 1.5},
  vat_percentage:{254:16},
  depreciation: {254:-10},
  //Body faults key: 0:None, 1:Minor, 2:Major
  body_faults: {0:0, 1:-2.5, 2: -5},
  engine_faults: -10,
  transmission_faults: -10,
  steering_faults: -3.5,
  //Demand factor - true: 1, false: 2, Average: 0
  demand_factor: {0:0, 1:10, 2:-7.5},
  unroadworthiness: -7.5,
  max_local_allowed_age: {254:7},
  depreciating_factor_by_vehicle_age: {254:{0:0.0115, 3: 0.615, 4: 0.585, 5: 0.56, 6: 0.54, 7: 0.52, 8: 0.495, 9: 0.47, 10: 0.45, 11: 0.43, 12: 0.41}},
  depreciation_by_use: {1: -10, 2:-15},
  high_mileage:{254:
    {1:{
      0:0,
      10000:5,
      20000:0,
      40000:-5,
      40001:-10 }
  }, 2:{
      50000:10,
      100000:-10}
    },

  //AWS
  aws_cognito_user: null,
};{code}

