# In order to have a referable table, we shall create a new table in our database where assessors can add base values from three categories:

* *import value* - this will be the importation cost of the vehicle based on make, model, model_class and year_of_manufacture.
* *local_value* - this will be the local government cost of the vehicle based on make, model, model_class and year_of_manufacture.
* *dealership_value_average* - this will be the local dealership cost of the vehicle based on make, model, model_class and year_of_manufacture. This input field can take more that one value, and when called, returns an average of the specific vehicle's dealership values
* *car yard value average*



{noformat}//Create a payload object
payload = ["make","model","year_of_manufacture","engine_rating", "country_of_origin", 
"country_of_valuation","years_in_country","year_of_registration,"year_of_manufacture","const_freight_value",
"const_grade_value","car_freight_amount",import_value","local_value","avg_dealership_value",
]

float func valuationLogic(payload){
  local_value = localValue(payload);
  import_value = apprecialteImportValue(payload);
  dealership_value = avg_dealership_value();
  variance_value = varianceValue(local_value, import_value, dealership_value);
  auto_calculated_value = previousValueVariace(variance_value, previous_value);
  return auto_calculated_value;
}

float func apprecialteImportValue(payload){
  import_value,car_freight_amount,years_in_country,engine_cc,country_of_valuation,grade
}

float func depreciateLocalValue(payload){
  //Assuming "Kenya" is ID 254 (can use international phone code)
  //Run kenyaLocalValuefunction
  //Note, different countries shall have different calculations for local value
  //This should be factored in while developing this
  //We shall have different local_value_logic for different countries
  case payload.country_of_origin_id = 254:
    kenyaLocalValue(payload);
  case payload.country_of_origin_id = xxx:  
    xxxLocalValue(payload);
  break;
}

